dream_query.sdl_delta:
extend type Query {
  """Yesterday's completed orders, filtered by an ISO date range or a relative token like 'yesterday'."""
  orderExports(dateRange: String!, limit: Int = 50): OrderExportConnection!
}

type OrderExportConnection {
  edges: [OrderExportEdge!]!
  pageInfo: PageInfo!
  totalCount: Int!
}

type OrderExportEdge {
  node: OrderExport!
  cursor: String!
}

type OrderExport {
  id: ID!
  orderNumber: String!
  placedAt: DateTime!
  totalCents: Int!
  currency: String!
  csvUrl: String!
}

type PageInfo {
  hasNextPage: Boolean!
  endCursor: String
}

scalar DateTime
